import { getAllProducts, getCatalogSyncState, queueCatalogSync } from '@/lib/catalog';

function formatDateTime(value: string | null) {
  if (!value) {
    return 'Not synced yet';
  }

  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
    timeZone: 'UTC'
  }).format(new Date(value));
}

export default async function Page() {
  const [products, syncState] = await Promise.all([getAllProducts(), getCatalogSyncState()]);

  async function syncLatestCatalog() {
    'use server';
    queueCatalogSync();
  }

  return (
    <main className="page-shell">
      <section className="hero">
        <div>
          <div className="eyebrow">
            <span className="eyebrow-dot" />
            Catalog Operations
          </div>
          <h1 className="title">Product catalog admin</h1>
          <p className="lede">
            Browse the current catalog quickly, keep working while ERP or PIM syncs run in the
            background, and let the shared <code>products</code> cache refresh on demand across
            every catalog view.
          </p>
        </div>

        <aside className="stats-panel">
          <div className="stats-grid">
            <div className="stat">
              <span className="stat-label">Catalog state</span>
              <span className="stat-value">
                {syncState.status === 'syncing' ? 'Syncing in background' : 'Ready for browsing'}
              </span>
            </div>
            <div className="stat">
              <span className="stat-label">Last sync</span>
              <span className="stat-value">{formatDateTime(syncState.lastSyncedAt)}</span>
            </div>
            <div className="stat">
              <span className="stat-label">Visible SKUs</span>
              <span className="stat-value">{products.length.toLocaleString()} products</span>
            </div>
          </div>
        </aside>
      </section>

      <section className="sync-panel">
        <div>
          <h2 className="sync-title">Sync latest catalog</h2>
          <p className="sync-copy">
            Trigger a background refresh when the upstream ERP or PIM changes pricing, inventory,
            or availability. The submission returns immediately, and catalog data converges shortly
            after without forcing every request to recompute.
          </p>
        </div>

        <form className="sync-form" action={syncLatestCatalog}>
          <button className="sync-button" type="submit" aria-disabled={syncState.status === 'syncing'}>
            {syncState.status === 'syncing' ? 'Sync already running' : 'Sync latest catalog'}
          </button>
          <div className="sync-status">
            {syncState.status === 'syncing'
              ? 'The catalog list may stay briefly stale while the shared cache is refreshed.'
              : 'Cached product data is reused between requests and invalidated by the products tag.'}
          </div>
        </form>
      </section>

      <section className="catalog-panel">
        <div className="catalog-header">
          <div>
            <h2>Catalog snapshot</h2>
            <p>Cached data shared across the admin product list and any other catalog view.</p>
          </div>
        </div>

        <div className="table-wrap">
          <table className="catalog-table">
            <thead>
              <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Inventory</th>
                <th>Availability</th>
                <th>Updated</th>
              </tr>
            </thead>
            <tbody>
              {products.map(product => (
                <tr key={product.id}>
                  <td>
                    <div className="product-name">{product.name}</div>
                    <div className="product-meta">SKU-{product.id.toString().padStart(4, '0')}</div>
                  </td>
                  <td className="price">${product.price.toLocaleString()}</td>
                  <td>{product.inventory.toLocaleString()} units</td>
                  <td>
                    <span className={`pill ${product.available ? 'available' : 'unavailable'}`}>
                      {product.available ? 'Available' : 'Out of stock'}
                    </span>
                  </td>
                  <td>{formatDateTime(product.updatedAt)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </main>
  );
}

