import { revalidateTag, unstable_cache } from 'next/cache';

export const CATALOG_TAG = 'products';

export type Product = {
  id: number;
  name: string;
  price: number;
  inventory: number;
  available: boolean;
  updatedAt: string;
};

type SyncState = {
  status: 'idle' | 'syncing';
  requestedAt: string | null;
  lastSyncedAt: string | null;
};

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

let productSource: Product[] = [
  {
    id: 1,
    name: 'Laptop',
    price: 999,
    inventory: 24,
    available: true,
    updatedAt: '2026-07-17T08:00:00.000Z'
  },
  {
    id: 2,
    name: 'Phone',
    price: 699,
    inventory: 43,
    available: true,
    updatedAt: '2026-07-17T08:00:00.000Z'
  },
  {
    id: 3,
    name: 'Tablet',
    price: 499,
    inventory: 12,
    available: true,
    updatedAt: '2026-07-17T08:00:00.000Z'
  },
  {
    id: 4,
    name: 'Headphones',
    price: 199,
    inventory: 68,
    available: true,
    updatedAt: '2026-07-17T08:00:00.000Z'
  },
  {
    id: 5,
    name: 'Watch',
    price: 299,
    inventory: 19,
    available: true,
    updatedAt: '2026-07-17T08:00:00.000Z'
  }
];

let syncState: SyncState = {
  status: 'idle',
  requestedAt: null,
  lastSyncedAt: '2026-07-17T08:00:00.000Z'
};

const getCachedProducts = unstable_cache(
  async () => {
    await delay(120);
    return productSource.map(product => ({ ...product }));
  },
  ['products'],
  {
    tags: [CATALOG_TAG]
  }
);

export async function getAllProducts() {
  return getCachedProducts();
}

export function getCatalogSyncState() {
  return {
    ...syncState
  };
}

function refreshProducts() {
  const now = new Date().toISOString();

  productSource = productSource.map(product => {
    const priceAdjustment = product.id % 2 === 0 ? 8 : 12;
    const inventoryAdjustment = product.id % 3 === 0 ? -2 : 3;
    const nextInventory = Math.max(0, product.inventory + inventoryAdjustment);

    return {
      ...product,
      price: product.price + priceAdjustment,
      inventory: nextInventory,
      available: nextInventory > 0,
      updatedAt: now
    };
  });

  syncState = {
    status: 'idle',
    requestedAt: syncState.requestedAt,
    lastSyncedAt: now
  };
}

export function queueCatalogSync() {
  if (syncState.status === 'syncing') {
    return;
  }

  const requestedAt = new Date().toISOString();

  syncState = {
    ...syncState,
    status: 'syncing',
    requestedAt
  };

  void (async () => {
    try {
      await delay(1500);
      refreshProducts();
      revalidateTag(CATALOG_TAG, 'max');
    } catch (error) {
      syncState = {
        ...syncState,
        status: 'idle'
      };
      console.error('Catalog sync failed', error);
    }
  })();
}
